={
  "name": "candidate_screening_analysis",
  "description": "Evaluation of a candidate's resume against a target Job Description for hiring managers.",
  "strict": true,
  "schema": {
    "type": "object",
    "properties": {
      "candidate_name": {
        "type": "string",
        "description": "The full name of the candidate. If not found, output 'Unknown'."
      },
      "email_address": {
        "type": "string",
        "description": "The email address of the candidate found in the CV. If not found, output 'Not Provided'."
      },
      "contact_phone": {
        "type": "string",
        "description": "The contact phone number of the candidate found in the CV. If not found, output 'Not Provided'."
      },
      "match_score": {
        "type": "integer",
        "description": "A score from 0 to 100 representing how well the candidate matches the job description."
      },
      "key_strengths": {
        "type": "array",
        "description": "Top 3 to 5 skills or experiences the candidate possesses that perfectly align with the JD.",
        "items": {
          "type": "string"
        }
      },
      "missing_qualifications": {
        "type": "array",
        "description": "Key skills, keywords, or requirements mentioned in the JD that are missing from the candidate's CV.",
        "items": {
          "type": "string"
        }
      },
      "recommendation": {
        "type": "string",
        "enum": [
          "Strong Hire",
          "Interview",
          "Keep in View",
          "Reject"
        ],
        "description": "The final hiring recommendation based strictly on the match score."
      },
      "executive_summary": {
        "type": "string",
        "description": "A 2-3 sentence objective summary for the Hiring Manager, explaining the score and whether the candidate should be interviewed."
      }
    },
    "required": [
      "candidate_name",
      "email_address",
      "contact_phone",
      "match_score",
      "key_strengths",
      "missing_qualifications",
      "recommendation",
      "executive_summary"
    ],
    "additionalProperties": false
  }
}

={
  "name": "resume_optimization_analysis",
  "description": "Evaluation of a job seeker's resume against a target Job Description to provide improvement feedback.",
  "strict": true,
  "schema": {
    "type": "object",
    "properties": {
      "job_seeker_name": {
        "type": "string",
        "description": "The full name found in the resume. If not found, output 'Unknown'."
      },
      "match_score": {
        "type": "integer",
        "description": "A score from 0 to 100 representing how well the current resume matches the target job description."
      },
      "key_strengths": {
        "type": "array",
        "description": "Top 3 to 5 skills or experiences currently on the resume that perfectly align with the job requirements.",
        "items": {
          "type": "string"
        }
      },
      "missing_keywords": {
        "type": "array",
        "description": "Key skills, keywords, or requirements mentioned in the JD that are missing or poorly highlighted in the resume.",
        "items": {
          "type": "string"
        }
      },
      "readiness_level": {
        "type": "string",
        "enum": [
          "Ready to Apply",
          "Needs Minor Tweaks",
          "Needs Major Revision",
          "Not a Good Fit"
        ],
        "description": "Assessment of how ready the resume is for submission based on the current match."
      },
      "actionable_feedback": {
        "type": "string",
        "description": "A 2-3 sentence summary explaining the score and providing specific advice on how to improve the resume for this role."
      }
    },
    "required": [
      "job_seeker_name",
      "match_score",
      "key_strengths",
      "missing_keywords",
      "readiness_level",
      "actionable_feedback"
    ],
    "additionalProperties": false
  }
}

